head.script:
// Preinitialize window.kapa object as per documentation: https://docs.kapa.ai/integrations/website-widget/javascript-api/preinitialize#setup
(function () {
    let k = window.Kapa;
    if (!k) {
        let i = function () {
            i.c(arguments);
        };
        i.q = [];
        i.c = function (args) {
            i.q.push(args);
        };
        window.Kapa = i;
    }
})();
